/// <summary>
/// Scoped service that holds wizard data for one applicant's session.
/// On Interactive Server, scoped = per circuit = per user connection.
/// </summary>
public class ApplicationState
{
    public PersonalInfoModel PersonalInfo { get; set; } = new();
    public List<ExperienceEntry> Experience { get; set; } = [new()];
    public List<ReferenceContact> References { get; set; } = [new()];

    // Track which steps have been explicitly saved.
    public HashSet<int> CompletedSteps { get; } = [];

    public void MarkStepCompleted(int step) => CompletedSteps.Add(step);
    public bool IsStepCompleted(int step) => CompletedSteps.Contains(step);
}

