@inherits LayoutComponentBase
@inject NavigationManager Nav

@* This layout renders statically (SSR). On each enhanced navigation it
   re-renders on the server, so reading the URL gives the current step. *@

<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        <div class="top-row px-4">
            <nav class="apply-progress" aria-label="Application progress">
                @for (int i = 0; i < Steps.Length; i++)
                {
                    var step = Steps[i];
                    var stepNumber = i + 1;
                    var css = stepNumber == CurrentStep ? "active"
                            : stepNumber < CurrentStep ? "completed"
                            : "upcoming";

                    <a href="@step.Href" class="apply-step @css">
                        <span class="step-number">@stepNumber</span>
                        <span class="step-label">@step.Label</span>
                    </a>

                    @if (stepNumber < Steps.Length)
                    {
                        <span class="step-connector @css"></span>
                    }
                }
                <span class="step-summary">Step @CurrentStep of @Steps.Length</span>
            </nav>
        </div>

        <article class="content px-4">
            @Body
        </article>
    </main>
</div>

<div id="blazor-error-ui" data-nosnippet>
    An unhandled error has occurred.
    <a href="." class="reload">Reload</a>
    <span class="dismiss">🗙</span>
</div>

@code {
    private static readonly (string Href, string Label)[] Steps =
    [
        ("/apply/personal-info", "Personal Info"),
        ("/apply/experience",    "Experience"),
        ("/apply/references",    "References"),
        ("/apply/review",        "Review"),
    ];

    private int CurrentStep
    {
        get
        {
            var path = new Uri(Nav.Uri).AbsolutePath.TrimEnd('/');
            for (int i = 0; i < Steps.Length; i++)
            {
                if (path.Equals(Steps[i].Href, StringComparison.OrdinalIgnoreCase))
                    return i + 1;
            }
            return 1;
        }
    }
}

.apply-progress {
    display: flex;
    align-items: center;
    gap: 0.25rem;
    flex-wrap: wrap;
}

