    display: flex;
    align-items: center;
    gap: 0.4rem;
    text-decoration: none;
    padding: 0.3rem 0.6rem;
    border-radius: 1rem;
    font-size: 0.85rem;
    color: #6c757d;
    transition: background-color 0.2s;
}

.apply-step:hover {
    background-color: #f0f0f0;
}

.step-number {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 1.6rem;
    height: 1.6rem;
    border-radius: 50%;
    border: 2px solid #dee2e6;
    font-weight: 600;
    font-size: 0.8rem;
}

.apply-step.active .step-number {
    background-color: #0d6efd;
    border-color: #0d6efd;
    color: white;
}

.apply-step.active .step-label {
    font-weight: 600;
    color: #0d6efd;
}

.apply-step.completed .step-number {
    background-color: #198754;
    border-color: #198754;
    color: white;
}

.apply-step.completed .step-label {
    color: #198754;
}

.step-connector {
    width: 1.5rem;
    height: 2px;
    background-color: #dee2e6;
}

.step-connector.completed {
    background-color: #198754;
}

.step-connector.active {
    background-color: #0d6efd;
}

.step-summary {
    margin-left: auto;
    font-size: 0.85rem;
    color: #6c757d;
    font-weight: 500;
}

