@page "/apply/personal-info"
@layout ApplyLayout
@rendermode InteractiveServer
@inject ApplicationState AppState
@inject NavigationManager Nav

<PageTitle>Personal Info – Apply</PageTitle>

<h1>Personal Information</h1>

<div class="mb-3">
    <label class="form-label">Full Name</label>
    <input class="form-control" @bind="AppState.PersonalInfo.Name" />
</div>

<div class="mb-3">
    <label class="form-label">Email</label>
    <input class="form-control" type="email" @bind="AppState.PersonalInfo.Email" />
</div>

<div class="d-flex justify-content-end">
    <button class="btn btn-primary" @onclick="Next">Next &rarr;</button>
</div>

@code {
    private void Next()
    {
        AppState.MarkStepCompleted(1);
        Nav.NavigateTo("/apply/experience");
    }
}

@page "/apply/experience"
@layout ApplyLayout
@rendermode InteractiveServer
@inject ApplicationState AppState
@inject NavigationManager Nav

<PageTitle>Experience – Apply</PageTitle>

<h1>Work Experience</h1>

@for (int i = 0; i < AppState.Experience.Count; i++)
{
    var entry = AppState.Experience[i];
    var index = i;

    <div class="card mb-3 p-3">
        <div class="d-flex justify-content-between align-items-center mb-2">
            <strong>Position @(index + 1)</strong>
            @if (AppState.Experience.Count > 1)
            {
                <button class="btn btn-sm btn-outline-danger" @onclick="() => Remove(index)">Remove</button>
            }
        </div>
        <div class="mb-2">
            <label class="form-label">Company</label>
            <input class="form-control" @bind="entry.Company" />
        </div>
        <div class="mb-2">
            <label class="form-label">Job Title</label>
            <input class="form-control" @bind="entry.Title" />
        </div>
        <div class="mb-2">
            <label class="form-label">Years</label>
            <input class="form-control" @bind="entry.Years" />
        </div>
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddEntry">+ Add Position</button>

<div class="d-flex justify-content-between">
    <button class="btn btn-outline-secondary" @onclick="Back">&larr; Back</button>
    <button class="btn btn-primary" @onclick="Next">Next &rarr;</button>
</div>

@code {
    private void AddEntry() => AppState.Experience.Add(new());

    private void Remove(int index) => AppState.Experience.RemoveAt(index);

    private void Back() => Nav.NavigateTo("/apply/personal-info");

    private void Next()
    {
        AppState.MarkStepCompleted(2);
        Nav.NavigateTo("/apply/references");
    }
}

@page "/apply/references"
@layout ApplyLayout
@rendermode InteractiveServer
@inject ApplicationState AppState
@inject NavigationManager Nav

<PageTitle>References – Apply</PageTitle>

<h1>References</h1>

@for (int i = 0; i < AppState.References.Count; i++)
{
    var contact = AppState.References[i];
    var index = i;

    <div class="card mb-3 p-3">
        <div class="d-flex justify-content-between align-items-center mb-2">
            <strong>Reference @(index + 1)</strong>
            @if (AppState.References.Count > 1)
            {
                <button class="btn btn-sm btn-outline-danger" @onclick="() => Remove(index)">Remove</button>
            }
        </div>
        <div class="mb-2">
            <label class="form-label">Name</label>
            <input class="form-control" @bind="contact.Name" />
        </div>
        <div class="mb-2">
            <label class="form-label">Relationship</label>
            <input class="form-control" @bind="contact.Relationship" />
        </div>
        <div class="mb-2">
            <label class="form-label">Phone</label>
            <input class="form-control" type="tel" @bind="contact.Phone" />
        </div>
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddReference">+ Add Reference</button>

<div class="d-flex justify-content-between">
    <button class="btn btn-outline-secondary" @onclick="Back">&larr; Back</button>
    <button class="btn btn-primary" @onclick="Next">Next &rarr;</button>
</div>

@code {
    private void AddReference() => AppState.References.Add(new());

    private void Remove(int index) => AppState.References.RemoveAt(index);

    private void Back() => Nav.NavigateTo("/apply/experience");

    private void Next()
    {
        AppState.MarkStepCompleted(3);
        Nav.NavigateTo("/apply/review");
    }
}

@page "/apply/review"
@layout ApplyLayout
@rendermode InteractiveServer
@inject ApplicationState AppState
@inject NavigationManager Nav

<PageTitle>Review – Apply</PageTitle>

<h1>Review Your Application</h1>

<section class="mb-4">
    <h4>Personal Information</h4>
    <dl class="row">
        <dt class="col-sm-3">Name</dt>
        <dd class="col-sm-9">@AppState.PersonalInfo.Name</dd>
        <dt class="col-sm-3">Email</dt>
        <dd class="col-sm-9">@AppState.PersonalInfo.Email</dd>
    </dl>
</section>

<section class="mb-4">
