    @foreach (var entry in AppState.Experience)
    {
        <div class="card mb-2 p-3">
            <strong>@entry.Title</strong> at @entry.Company — @entry.Years years
        </div>
    }
</section>

<section class="mb-4">
    <h4>References</h4>
    @foreach (var contact in AppState.References)
    {
        <div class="card mb-2 p-3">
            <strong>@contact.Name</strong> (@contact.Relationship) — @contact.Phone
        </div>
    }
</section>

<div class="d-flex justify-content-between">
    <button class="btn btn-outline-secondary" @onclick="Back">&larr; Back</button>
    <button class="btn btn-success" @onclick="Submit">Submit Application</button>
</div>

@code {
    private void Back() => Nav.NavigateTo("/apply/references");

    private void Submit()
    {
        // TODO: persist the application to a database
