@page "/apply/experience"
@layout ApplyLayout
@rendermode InteractiveServer
@inject ApplicationState AppState
@inject NavigationManager Nav

<PageTitle>Experience – Apply</PageTitle>

<h1>Work Experience</h1>

@for (int i = 0; i < AppState.Experience.Count; i++)
{
    var entry = AppState.Experience[i];
    var index = i;

    <div class="card mb-3 p-3">
        <div class="d-flex justify-content-between align-items-center mb-2">
            <strong>Position @(index + 1)</strong>
            @if (AppState.Experience.Count > 1)
            {
                <button class="btn btn-sm btn-outline-danger" @onclick="() => Remove(index)">Remove</button>
            }
        </div>
        <div class="mb-2">
            <label class="form-label">Company</label>
            <input class="form-control" @bind="entry.Company" />
        </div>
        <div class="mb-2">
            <label class="form-label">Job Title</label>
            <input class="form-control" @bind="entry.Title" />
        </div>
        <div class="mb-2">
            <label class="form-label">Years</label>
            <input class="form-control" @bind="entry.Years" />
        </div>
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddEntry">+ Add Position</button>

<div class="d-flex justify-content-between">
    <button class="btn btn-outline-secondary" @onclick="Back">&larr; Back</button>
    <button class="btn btn-primary" @onclick="Next">Next &rarr;</button>
</div>

@code {
    private void AddEntry() => AppState.Experience.Add(new());

    private void Remove(int index) => AppState.Experience.RemoveAt(index);

    private void Back() => Nav.NavigateTo("/apply/personal-info");

    private void Next()
    {
        AppState.MarkStepCompleted(2);
        Nav.NavigateTo("/apply/references");
    }
}

